import java.util.*

fun solve(n: Long, edges: Array<Array<Long>>, source: Long, target: Long, k: Long): Long {
    if (source == target) {
        return 0L
    }

    val nInt = n.toInt()
    val kInt = k.toInt()

    val allWeights = mutableSetOf<Long>()
    for (edge in edges) {
        allWeights.add(edge[2])
    }

    // Potential thresholds are 0 and all unique edge weights.
    val sortedWeights = (allWeights.toMutableList() + 0L).toSortedSet().toList()

    // Helper function to check reachability for a given threshold
    fun canReach(threshold: Long): Boolean {
        // BFS on state (node, heavy_edge_count)
        // visited[node][heavy_count] = true if reachable
        val visited = Array(nInt) { BooleanArray(kInt + 1) { false } }

        // Queue stores Pair(node, heavy_count)
        val queue: Queue<Pair<Int, Int>> = LinkedList()

        queue.add(Pair(source.toInt(), 0))
        visited[source.toInt()][0] = true

        while (queue.isNotEmpty()) {
            val (u, heavyCount) = queue.poll()

            if (u == target.toInt()) {
                return true
            }

            // Iterate through all edges to find neighbors of u
            for (edge in edges) {
                var uEdge = edge[0].toInt()
                var vEdge = edge[1].toInt()
                val w = edge[2]

                var v = -1
                var isHeavy = w > threshold

                if (uEdge == u) {
                    v = vEdge.toInt()
                } else if (vEdge == u) {
                    v = uEdge.toInt()
                } else {
                    continue // Edge does not involve u
                }

                val newHeavyCount = heavyCount + if (isHeavy) 1 else 0

                if (newHeavyCount <= kInt && !visited[v][newHeavyCount]) {
                    visited[v][newHeavyCount] = true
                    queue.add(Pair(v, newHeavyCount))
                }
            }
        }

        return false
    }

    // 1. Check if any path exists at all (i.e., with threshold >= max_weight, so all edges are light)
    // We use a threshold larger than any possible weight to ensure all edges are light.
    val maxWeight = if (allWeights.isNotEmpty()) allWeights.maxOrNull()!! else 0L
    val allLightThreshold = maxWeight + 1L

    if (!canReach(allLightThreshold)) {
        return -1L
    }

    // 2. Binary Search over the sorted unique potential thresholds
    // We search over the indices of sortedWeights to find the smallest threshold T that works.

    var low = 0
    var high = sortedWeights.size - 1
    var minThreshold = -1L

    while (low <= high) {
        val midIndex = low + (high - low) / 2
        val midThreshold = sortedWeights[midIndex]

        if (canReach(midThreshold)) {
            // midThreshold works. This is a candidate for the minimum. Try smaller.
            minThreshold = midThreshold
            high = midIndex - 1
        } else {
            // midThreshold is too small. Need a larger threshold.
            low = midIndex + 1
        }
    }

    return minThreshold
}
