    // Search range: [L, R]
    // L = 0 (minimum possible threshold)
    // R = maxWeight (If threshold >= maxWeight, all edges are light, which is the most permissive case)

    var low: Long = 0L
    var high: Long = maxWeight
    var minThreshold: Long = -1L

    // Check if any path exists at all (using threshold = maxWeight, so all edges are light)
    if (!canReach(maxWeight)) {
