function solve(n, edges, source, target, k) {
    if (source === target) {
        return 0;
    }

    // Collect all unique edge weights to form the search space for threshold
    let weights = new Set();
    for (const [, , w] of edges) {
        weights.add(w);
    }
    // Add 0 as a potential minimum threshold if all weights are positive, 
    // though binary search on sorted unique weights handles this implicitly if we check the smallest weight.
    // Since weights >= 1, including 0 is fine as a lower bound for the search space.
    const sortedWeights = Array.from(weights).sort((a, b) => a - b);

    // The search space for the minimum threshold T is [0, max_weight]
    // We will binary search over the potential threshold values (which are related to edge weights).

    /**
     * Checks if a path from source to target exists with at most k heavy edges
     * given a specific threshold.
     * @param {number} threshold
     * @returns {boolean}
     */
    const canReach = (threshold) => {
        // We use a variation of BFS/Dijkstra where the state is (node, heavy_edge_count)
        // Since edge weights are only used to determine heavy/light, and we only care about reachability
        // with a constraint on heavy edges, BFS is appropriate.

        // dist[i][j] stores whether node i is reachable using exactly j heavy edges.
        // We only need to track reachability, so a boolean array is sufficient.
        // However, since we are looking for *any* path, we can use a visited array for the state (node, heavy_count).

        // visited[node][heavy_count] = true if reachable
        const visited = Array(n).fill(0).map(() => Array(k + 1).fill(false));

        // Queue stores [node, heavy_count]
        const queue = [[source, 0]];
        visited[source][0] = true;

        while (queue.length > 0) {
            const [u, heavyCount] = queue.shift();

            if (u === target) {
                return true; // Found a path within the heavy edge limit k
            }

            for (const [u_edge, v_edge, w] of edges) {
                let v, isHeavy;
                if (u_edge === u) {
                    v = v_edge;
                    isHeavy = w > threshold;
                } else if (v_edge === u) {
                    v = u_edge;
                    isHeavy = w > threshold;
                } else {
                    continue; // Edge does not involve u
                }

                const newHeavyCount = heavyCount + (isHeavy ? 1 : 0);

                if (newHeavyCount <= k && !visited[v][newHeavyCount]) {
                    visited[v][newHeavyCount] = true;
                    queue.push([v, newHeavyCount]);
                }
            }
        }

        return false;
    };

    // ---------------------------------------------------------------------
    // Binary Search Implementation
    // Search space: [L, R]. We are looking for the smallest T such that canReach(T) is true.
    // Potential thresholds include 0 and all edge weights.
    // To cover all possibilities, we search over the range of weights [0, max_weight + 1].

    let low = 0;
    // Maximum possible weight + 1 to ensure we test a threshold greater than any actual edge weight
    let high = sortedWeights.length > 0 ? sortedWeights[sortedWeights.length - 1] + 1 : 1; 
    let minThreshold = -1;

    // If there are no edges, and source != target, we can't reach the target.
    if (edges.length === 0 && source !== target) {
        return -1;
    }

    // Check if reachability is possible even with the highest possible threshold 
    // (i.e., all edges are light, threshold >= max_weight).
    // If it's not reachable even when all edges are light, then it's impossible regardless of threshold.
    if (!canReach(high)) {
        // If we cannot reach it even when the threshold is effectively infinite (all edges are light), 
        // then there is no path.
        return -1;
    }


    // Binary search over the potential threshold values (the weights + 0)
    // Since we are searching for the MINIMUM threshold, we try to push 'low' up as long as canReach is true.
    while (low <= high) {
        // Use floor for mid to avoid potential infinite loops if high - low is 1
        let mid = Math.floor((low + high) / 2);

        if (canReach(mid)) {
            // 'mid' is a possible answer. Try for a smaller threshold.
            minThreshold = mid;
            high = mid - 1;
        } else {
            // 'mid' is too small; we need a higher threshold to turn some edges into light edges.
            low = mid + 1;
        }
    }

    return minThreshold;
